import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';
import { danhGiaAPI, nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './HoSoCaNhan.css';

const fmt = n => new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(n || 0);

const normalizeName = value => value.trim().replace(/\s+/g, ' ');
const isValidName = value => {
  const normalized = normalizeName(value);
  return normalized.length >= 2 && normalized.length <= 100 && !/\d/.test(normalized);
};
const isValidPhone = value => /^\d{10,11}$/.test(value);

export default function HoSoCaNhan() {
  const { user, layThongTinToi } = useAuthStore();
  const [editing, setEditing] = useState(false);
  const [form, setForm] = useState({ hoTen: '', soDienThoai: '' });
  const [saving, setSaving] = useState(false);
  const [danhGias, setDanhGias] = useState([]);
  const [loadingDanhGia, setLoadingDanhGia] = useState(true);

  useEffect(() => {
    setForm({
      hoTen: user?.hoTen || '',
      soDienThoai: user?.soDienThoai || '',
    });
  }, [user]);

  useEffect(() => {
    let active = true;

    danhGiaAPI.layNhanDuoc()
      .then(res => {
        if (active) {
          setDanhGias(res.data.data || []);
        }
      })
      .catch(() => {})
      .finally(() => {
        if (active) {
          setLoadingDanhGia(false);
        }
      });

    return () => {
      active = false;
    };
  }, []);

  const handleSave = async () => {
    const hoTen = normalizeName(form.hoTen);
    const soDienThoai = form.soDienThoai.trim();

    if (!isValidName(hoTen)) {
      toast.error('Ho ten phai tu 2-100 ky tu va khong duoc chua so');
      return;
    }

    if (!isValidPhone(soDienThoai)) {
      toast.error('So dien thoai phai gom 10 hoac 11 chu so');
      return;
    }

    setSaving(true);
    try {
      await nguoiDungAPI.capNhat({ ...form, hoTen, soDienThoai });
      await layThongTinToi();
      toast.success('Cap nhat thanh cong');
      setEditing(false);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Cap nhat that bai');
    } finally {
      setSaving(false);
    }
  };

  const handleAvatarChange = async e => {
    const file = e.target.files[0];
    if (!file) return;

    const fd = new FormData();
    fd.append('file', file);

    try {
      await nguoiDungAPI.uploadAvatar(fd);
      await layThongTinToi();
      toast.success('Cap nhat anh dai dien thanh cong');
    } catch (error) {
      toast.error(error.response?.data?.message || 'Upload that bai');
    }
  };

  if (!user) return <div className="spinner" />;

  const danhGiaHienThi = [...danhGias]
    .sort((a, b) => new Date(b.ngayDanhGia || 0) - new Date(a.ngayDanhGia || 0))
    .slice(0, 5);

  return (
    <div className="container page-wrapper">
      <div className="hoso-layout">
        <div className="card profile-card">
          <div className="card-body" style={{ textAlign: 'center' }}>
            <div className="avatar-upload">
              <img
                src={user.avatar || `https://ui-avatars.com/api/?name=${encodeURIComponent(user.hoTen)}&background=12355B&color=fff&size=120`}
                className="avatar avatar-xl"
                alt=""
              />
              <label htmlFor="avatar-input" className="avatar-edit-btn" title="Doi anh">✏️</label>
              <input id="avatar-input" type="file" accept="image/*" hidden onChange={handleAvatarChange} />
            </div>

            <h2 style={{ marginTop: 16, fontWeight: 800 }}>{user.hoTen}</h2>
            <div style={{ marginTop: 12, fontSize: 14, color: 'var(--text-muted)' }}>
              Trang cong khai cua ban chi hien thi cho user khac khi ho bam vao ten hoac avatar cua ban.
            </div>

            {user.xacThuc ? (
              <span className="badge badge-success" style={{ marginTop: 8 }}>Da xac thuc CCCD</span>
            ) : (
              <Link
                to="/xac-thuc"
                className="badge badge-warning"
                style={{ marginTop: 8, cursor: 'pointer', textDecoration: 'none' }}
              >
                Chua xac thuc - Xac thuc ngay
              </Link>
            )}

            <div style={{ marginTop: 14 }}>
              {user.diemDanhGia ? (
                <div className="stars">
                  {'★'.repeat(Math.round(user.diemDanhGia))}
                  {'☆'.repeat(5 - Math.round(user.diemDanhGia))}
                  <span style={{ fontSize: 14, color: 'var(--text-muted)', marginLeft: 6 }}>
                    {user.diemDanhGia.toFixed(1)} / 5
                  </span>
                </div>
              ) : (
                <div style={{ color: 'var(--text-muted)', fontSize: 14 }}>Chua co danh gia nao</div>
              )}
            </div>

            <div style={{ marginTop: 20, padding: '16px 0', borderTop: '1px solid var(--border)' }}>
              <div style={{ fontSize: 13, color: 'var(--text-muted)' }}>So du vi</div>
              <div style={{ fontSize: 24, fontWeight: 800, color: 'var(--primary)' }}>{fmt(user.soDuVi)}</div>
              <div className="profile-wallet-actions">
                <Link to="/thanh-toan" className="btn btn-outline btn-sm">Nap tien</Link>
                <Link to="/hoa-don" className="btn btn-outline btn-sm">Hoa don</Link>
              </div>
            </div>
          </div>
        </div>

        <div>
          <div className="card">
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span>Thong tin ca nhan</span>
              {!editing ? (
                <button className="btn btn-outline btn-sm" onClick={() => setEditing(true)}>Chinh sua</button>
              ) : (
                <div style={{ display: 'flex', gap: 8 }}>
                  <button className="btn btn-primary btn-sm" onClick={handleSave} disabled={saving}>
                    {saving ? 'Dang luu...' : 'Luu'}
                  </button>
                  <button
                    className="btn btn-secondary btn-sm"
                    onClick={() => {
                      setEditing(false);
                      setForm({
                        hoTen: user?.hoTen || '',
                        soDienThoai: user?.soDienThoai || '',
                      });
                    }}
                  >
                    Huy
                  </button>
                </div>
              )}
            </div>
            <div className="card-body">
              {editing ? (
                <>
                  <div className="form-group">
                    <label className="form-label">Ho va ten</label>
                    <input
                      className="form-control"
                      maxLength={100}
                      value={form.hoTen}
                      onChange={e => setForm(current => ({ ...current, hoTen: e.target.value }))}
                    />
                  </div>
                  <div className="form-group">
                    <label className="form-label">So dien thoai</label>
                    <input
                      className="form-control"
                      inputMode="numeric"
                      pattern="[0-9]{10,11}"
                      maxLength={11}
                      value={form.soDienThoai}
                      onChange={e => setForm(current => ({ ...current, soDienThoai: e.target.value.replace(/\D/g, '') }))}
                    />
                  </div>
                </>
              ) : (
                <div>
                  {[
                    ['Ho ten', user.hoTen],
                    ['Email', user.email],
                    ['Dien thoai', user.soDienThoai || 'Chua cap nhat'],
                    ['Ngay tham gia', user.ngayTao ? new Date(user.ngayTao).toLocaleDateString('vi-VN') : ''],
                  ].map(([label, value]) => (
                    <div key={label} className="info-row">
                      <span style={{ color: 'var(--text-muted)' }}>{label}</span>
                      <strong>{value}</strong>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header" style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
              <span>Danh gia nhan duoc</span>
              <Link to="/danh-gia" className="btn btn-outline btn-sm">Quan ly danh gia</Link>
            </div>
            <div className="card-body">
              {loadingDanhGia ? (
                <div style={{ color: 'var(--text-muted)' }}>Dang tai danh gia...</div>
              ) : danhGiaHienThi.length === 0 ? (
                <div className="review-empty">
                  Ho so hien chua co danh gia nao danh cho ban.
                </div>
              ) : (
                <div className="review-list">
                  {danhGiaHienThi.map(dg => (
                    <div key={dg.maDanhGia} className="review-item">
                      <div className="review-top">
                        <strong>{dg.tenNguoiDanhGia || 'Nguoi dung an danh'}</strong>
                        <span className="stars">{'★'.repeat(dg.soSao)}{'☆'.repeat(5 - dg.soSao)}</span>
                      </div>
                      <div style={{ color: 'var(--text-muted)', marginTop: 6 }}>
                        {dg.moTa || 'Khong co nhan xet chi tiet'}
                      </div>
                      <div className="review-date">
                        {dg.ngayDanhGia ? new Date(dg.ngayDanhGia).toLocaleDateString('vi-VN') : ''}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>

          <div className="card" style={{ marginTop: 20 }}>
            <div className="card-header">Hanh dong nhanh</div>
            <div className="card-body">
              <div className="quick-actions">
                {[
                  ['/quan-ly-phong', '🏠', 'Quan ly phong'],
                  ['/quan-ly-bai-dang', '📝', 'Quan ly bai dang'],
                  ['/yeu-cau', '📋', 'Yeu cau cua toi'],
                  ['/thanh-toan', '💰', 'Vi tien'],
                  ['/hoa-don', '📄', 'Hoa don cua toi'],
                  ['/tam-tru', '📑', 'Phieu tam tru'],
                  ['/danh-gia', '⭐', 'Danh gia'],
                  ['/xac-thuc', '🔐', 'Xac thuc CCCD'],
                ].map(([to, icon, label]) => (
                  <Link key={to} to={to} className="quick-action-btn">
                    <span>{icon}</span>
                    <span>{label}</span>
                  </Link>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
